    const user = findUserByEmail(email);
    if (!user || user.password !== password) {
        return { user: null, error: 'Invalid email or password.' };
    }
    if (user.role === 'agent' && !user.isVerified) {
        return { user: null, error: 'pending_verification_agent' };
